const testPools={
operatoria:[q('¿Qué caracteriza a la escritura al tacto?',['Se basa en pulsar las teclas sin necesidad de mirar el teclado, gracias al conocimiento de su posición.','Consiste en escribir deprisa aunque se cometan muchos errores y luego corregirlos al final.','Se apoya en mirar constantemente las manos para memorizar cada tecla de forma visual.','Se realiza únicamente con dos dedos mientras el resto permanece sin intervenir.'],0),q('¿Cuál de estos principios básicos aparece en el aprendizaje de la mecanografía al tacto?',['Cambiar de postura con frecuencia para no acostumbrarse a una sola posición.','Pasar al siguiente ejercicio aunque el anterior tenga errores para ganar velocidad cuanto antes.','No mirar al teclado y repetir los ejercicios las veces indicadas hasta realizarlos correctamente.','Utilizar siempre la tecla de borrado para corregir cada pequeño fallo durante el entrenamiento.'],2),q('¿Qué finalidad tiene la constancia en el aprendizaje mecanográfico?',['Permitir que se consoliden hábitos correctos mediante una práctica diaria y regular.','Sustituir la concentración por un trabajo más automático desde el primer día.','Evitar que el alumnado tenga que memorizar la posición de las teclas.','Reducir la importancia de la precisión frente a la velocidad.'],0),q('¿Qué significa pulcritud en mecanografía?',['Escribir con adornos tipográficos para que el texto sea más vistoso.','Escribir rápido, aunque el texto esté lleno de errores, para ahorrar tiempo.','Cuidar la corrección del texto, porque de poco sirve la velocidad si luego hay que perder tiempo corrigiendo muchos fallos.','Mantener el teclado muy limpio antes de empezar a escribir.'],2),q('¿Qué teclas sirven como referencia principal para colocar los índices en el teclado alfanumérico?',['Las teclas A y Ñ.','Las teclas F y J.','Las teclas Q y P.','Las teclas 4 y 6 del teclado numérico.'],1),q('¿Por qué el teclado más común recibe el nombre de QWERTY?',['Porque son las seis letras que aparecen en la fila central del teclado.','Porque identifica exclusivamente a los teclados inalámbricos.','Porque corresponde a las primeras letras de la fila superior de teclas.','Porque es la abreviatura técnica del teclado extendido profesional.'],2),q('¿Qué función tiene la barra espaciadora en la escritura?',['Separar palabras entre sí, pulsándola preferentemente con el pulgar de la mano contraria a la última que actuó.','Activar el teclado numérico cuando está bloqueado.','Borrar el carácter situado a la izquierda del cursor.','Mover el punto de inserción al principio del documento.'],0),q('¿Cuál es una función habitual de la tecla Tab en editores de texto y formularios?',['Activar las mayúsculas de forma permanente.','Agregar un espacio de tabulación o saltar de un componente a otro.','Cerrar la ventana activa al combinarla con Alt.','Mostrar la ayuda del programa como la tecla F1.'],1),q('¿Qué hace normalmente la tecla Retroceso?',['Borra el carácter situado a la izquierda del punto de inserción.','Borra el carácter situado a la derecha del cursor sin moverlo.','Inserta espacios automáticos al comienzo de la línea.','Abre el menú contextual del elemento seleccionado.'],0),q('¿Qué diferencia principal hay entre Retroceso y Supr?',['Retroceso y Supr realizan exactamente la misma función en todos los programas.','Retroceso borra a la izquierda y Supr borra a la derecha del punto de inserción.','Retroceso mueve el cursor y Supr activa el teclado numérico.','Retroceso inserta caracteres y Supr cambia a modo sobrescritura.'],1),q('¿Qué permite hacer normalmente la combinación Alt + F4 en Windows?',['Abrir el menú Inicio.','Imprimir la página actual.','Cerrar la ventana activa.','Seleccionar todo el contenido de la ventana.'],2),q('¿Qué ocurre cuando Bloq Num está activado?',['Se bloquean todas las teclas del teclado extendido.','Se activa la función numérica de las teclas del bloque numérico derecho.','Las teclas alfabéticas pasan automáticamente a mayúsculas.','Las teclas de función dejan de responder.'],1),q('¿Qué estructura general presenta un teclado extendido?',['Se divide en zona alfanumérica, teclas de función, teclas numéricas y teclas de movimiento del cursor.','Se divide únicamente en letras, números y signos de puntuación.','Se compone solo de una zona principal y de la barra espaciadora.','Se reparte en área táctil, zona multimedia y panel de impresión.'],0),q('¿Por qué conviene no levantar los dedos de su posición si no es necesario?',['Porque así es más fácil mantener la referencia del teclado y evitar mirar las teclas.','Porque mejora el brillo de las señales luminosas del teclado.','Porque impide que se utilice correctamente la barra espaciadora.','Porque obliga a usar siempre el mismo pulgar.'],0),q('¿Qué objetivo tienen los ejercicios de repetición de palabras con combinaciones difíciles?',['Aumentar la cantidad de texto escrito aunque haya errores.','Rectificar malos hábitos adquiridos durante el aprendizaje mecanográfico.','Reducir la necesidad de conocer la posición de las teclas.','Sustituir el uso de programas de práctica mecanográfica.'],1),q('¿Qué programa o recurso de práctica aparece citado como apoyo para desarrollar la destreza mecanográfica?',['TypingClub o programas específicos de mecanografía asistida.','Una hoja de cálculo para contar teclas manualmente.','Un visor de imágenes para observar el teclado.','Un sistema operativo sin conexión a Internet.'],0),q('¿Qué tecla equivale al botón Inicio de Windows?',['Esc.','Alt Gr.','Windows.','Insert.'],2),q('¿Qué función puede tener Enter según el contenido estudiado?',['Introducir datos, confirmar una opción o pasar a la línea siguiente.','Activar la navegación privada del navegador.','Bloquear el teclado numérico.','Modificar el brillo de la pantalla.'],0),q('¿Cuál de estas afirmaciones sobre el teclado numérico es correcta?',['Solo puede usarse si la pantalla está apagada.','Su distribución de dedos toma como referencia la tecla 5, que tiene una protuberancia.','Se maneja con ambas manos de forma simultánea en la mayoría de los casos.','No forma parte del teclado extendido.'],1),q('¿Qué ventaja tiene escribir rápido y correctamente en contextos administrativos?',['Permite elaborar informes, cartas o facturas con mayor eficiencia y menor necesidad de corrección posterior.','Hace innecesario revisar documentos antes de entregarlos.','Sustituye totalmente el aprendizaje de ortografía y gramática.','Evita que haya que conocer el funcionamiento de las teclas.'],0)],
ergonomia:[q('¿Cuál es una recomendación postural básica al escribir en el teclado?',['Mantener la espalda recta y la cabeza alta.','Inclinar el tronco hacia delante para acercarse más al teclado.','Separar mucho los codos del cuerpo para moverse mejor.','Apoyar las muñecas con fuerza sobre el borde de la mesa.'],0),q('¿Dónde debe dirigirse la vista durante la escritura al tacto?',['A las manos para confirmar cada pulsación.','Al texto que se escribe y no al teclado.','A la barra espaciadora en cada cambio de palabra.','A las señales luminosas del teclado.'],1),q('¿Qué relación deben guardar los codos respecto al cuerpo?',['Deben quedar casi pegados al cuerpo formando un ángulo recto.','Deben mantenerse levantados por encima de los hombros.','Deben quedar muy separados para facilitar el movimiento lateral.','No importa su posición mientras la velocidad sea alta.'],0),q('¿Qué se recomienda sobre las manos y los dedos?',['Tensarlos para pulsar con más energía.','Mantenerlos completamente extendidos para llegar a más teclas.','Tenerlos relajados y ligeramente doblados, sin golpear las teclas con fuerza.','Moverlos bruscamente para ganar rapidez.'],2),q('¿Qué distancia aproximada deben guardar los ojos respecto al monitor o documento?',['Entre 40 y 70 centímetros aproximadamente.','Menos de 20 centímetros para ver con detalle las teclas.','Más de un metro para evitar reflejos.','Exactamente 10 centímetros en cualquier situación.'],0),q('¿Qué característica debe cumplir el teclado según las recomendaciones ergonómicas?',['Debe ser fijo y unido a la pantalla para ocupar menos espacio.','Debe ser inclinable e independiente de la pantalla.','Debe ser brillante para reflejar mejor la luz.','Debe quedar apoyado sobre las piernas del usuario.'],1),q('¿Por qué debe existir espacio suficiente delante del teclado?',['Para apoyar cómodamente brazos y manos durante el trabajo.','Para colocar el móvil junto a la barra espaciadora.','Para aumentar el ruido de las pulsaciones.','Para poder acercar el monitor hasta tocar el teclado.'],0),q('¿Qué se recomienda sobre la superficie del teclado?',['Que sea mate para evitar reflejos molestos.','Que sea metálica y muy brillante.','Que tenga iluminación intensa permanentemente.','Que esté cubierta con una tela gruesa.'],0),q('¿Qué requisito se señala para el asiento de trabajo?',['Debe ser estable, con libertad de movimiento y altura regulable.','Debe ser rígido y sin posibilidad de ajuste.','Debe obligar al usuario a permanecer completamente inmóvil.','Debe tener el respaldo fijo y completamente vertical.'],0),q('¿Qué opción puede mejorar la postura de algunas personas usuarias?',['Un reposapiés cuando sea necesario.','Una mesa más baja que el asiento.','Trabajar siempre de pie frente al teclado.','Cruzar las piernas para elevar las rodillas.'],0),q('¿Qué objetivo persigue el marco ergonómico aplicado a puestos informatizados?',['Que el uso del equipo no sea una fuente de riesgo para la salud.','Que todas las personas utilicen exactamente la misma mesa y la misma silla.','Que el trabajador reduzca al mínimo el tiempo de descanso.','Que el teclado se use con mayor fuerza para mejorar la velocidad.'],0),q('¿Cuál es una pauta razonable de descanso en jornadas largas con ordenador?',['Cinco minutos de pausa por cada hora de trabajo aproximadamente.','Una pausa de treinta segundos al final de la jornada.','No hacer pausas para no perder el ritmo de trabajo.','Dos horas seguidas de descanso tras veinte minutos de trabajo.'],0),q('¿Qué se aconseja hacer durante los descansos?',['Seguir usando el smartphone para cambiar de pantalla.','Dar un pequeño paseo y estirar cuello, espalda y piernas.','Permanecer en la misma postura para descansar menos.','Aprovechar para escribir más rápido.'],1),q('¿Qué puede ocurrir si la altura de la mesa y la silla no guardan una relación adecuada?',['La escritura se vuelve más relajada y automática.','Se facilita el apoyo correcto de brazos y codos.','Se incrementa el riesgo de fatiga y repercute negativamente en la salud y el trabajo.','Se elimina la necesidad de hacer descansos.'],2),q('¿Qué afirmación describe mejor una postura correcta ante el teclado?',['Espalda recta, brazos próximos al cuerpo, cabeza alta y vista al texto.','Hombros elevados, cuello flexionado y ojos fijos en las teclas.','Apoyo continuo del peso corporal sobre las muñecas.','Tronco girado para alcanzar mejor la pantalla y el ratón.'],0),q('¿Por qué es importante no teclear con fuerza excesiva?',['Porque ayuda a mantener las manos relajadas y reduce tensiones innecesarias.','Porque así se bloquea menos la tecla Enter.','Porque solo el teclado numérico admite pulsaciones suaves.','Porque el monitor se mantiene más estable.'],0),q('¿Qué relación guarda la ergonomía con el rendimiento mecanográfico?',['Una postura cómoda favorece la salud, reduce fatiga y facilita escribir correctamente.','La ergonomía solo influye en el diseño del monitor y no en el teclado.','La ergonomía sustituye a la práctica diaria de mecanografía.','La ergonomía tiene importancia solo en trabajos manuales, no en tareas informáticas.'],0),q('¿Cuál de estas medidas se relaciona con la prevención de molestias visuales?',['Mantener una distancia adecuada de la pantalla y orientar bien la mirada.','Mirar alternativamente al teclado y a la mesa cada pocos segundos.','Subir al máximo el brillo sin revisar reflejos.','Reducir la distancia al monitor lo más posible.'],0),q('¿Qué debe permitir un buen asiento de trabajo?',['Libertad de movimiento y una postura confortable.','Bloquear completamente la movilidad del usuario.','Impedir el ajuste del respaldo para que la postura no cambie.','Elevar los codos por encima del teclado.'],0),q('¿Cuál es el enfoque más adecuado respecto al entorno de trabajo informatizado?',['Adaptar el puesto y sus elementos para que la interacción persona ordenador sea segura y cómoda.','Conceder prioridad absoluta a la velocidad, aunque la postura sea incorrecta.','Utilizar cualquier silla si el teclado funciona correctamente.','Separar el teclado lo menos posible de la pantalla aunque resulte incómodo.'],0)],
sistema:[q('¿Qué se entiende por informática según el contenido trabajado?',['La ciencia encargada del estudio y desarrollo del tratamiento automático de la información.','La técnica dedicada exclusivamente a reparar ordenadores averiados.','Un sistema para escribir textos muy rápidos en el teclado numérico.','La parte física de un equipo informático y nada más.'],0),q('¿Qué es un bit?',['La unidad mínima de información representada por un 0 o un 1.','Un conjunto de ocho bytes.','Una carpeta del sistema operativo.','Un programa para analizar amenazas.'],0),q('¿Qué relación existe entre bit y byte?',['Un byte está formado por ocho bits.','Un bit equivale a ocho bytes.','Un byte sustituye a la memoria del sistema operativo.','No existe relación entre ambos conceptos.'],0),q('¿Qué se entiende por hardware?',['La estructura física del sistema informático: componentes mecánicos y electrónicos.','El conjunto de licencias gratuitas instaladas en el equipo.','La interfaz gráfica del usuario en Windows 11.','La parte lógica de los programas que no puede tocarse.'],0),q('¿Qué se entiende por software?',['La parte lógica o intangible del ordenador: aplicaciones y programas.','Solo los periféricos de entrada y salida.','El conjunto de cables y puertos del sistema.','La torre o CPU exclusivamente.'],0),q('¿Qué función cumple el sistema operativo?',['Es el software imprescindible que permite al usuario interactuar con el ordenador y gestionar recursos.','Es una aplicación opcional que solo sirve para navegar por Internet.','Solo almacena archivos multimedia y documentos temporales.','Sustituye a todos los programas instalados en el equipo.'],0),q('¿Cuál de las siguientes es una función propia del sistema operativo?',['Gestionar hardware, procesos, memoria, periféricos, archivos y permisos.','Fabricar físicamente los componentes del equipo.','Crear por sí mismo documentos comerciales sin intervención del usuario.','Eliminar la necesidad de instalar actualizaciones de seguridad.'],0),q('¿Qué novedad o rasgo de Windows 11 se menciona en el material?',['Una interfaz más visual, con iconos centrados en la barra de tareas y escritorios virtuales.','La desaparición completa del Explorador de archivos.','La sustitución del ratón por comandos de voz obligatorios.','La eliminación del panel de configuración del sistema.'],0),q('¿Para qué sirven los escritorios virtuales en Windows 11?',['Para organizar el trabajo en espacios diferenciados según tareas o contextos.','Para sustituir el disco duro del equipo.','Para analizar virus mediante Microsoft Defender.','Para crear cuentas de usuario automáticamente.'],0),q('¿Qué permiten Snap Layouts en Windows 11?',['Organizar y distribuir ventanas de forma rápida en la pantalla.','Borrar definitivamente el historial del navegador.','Actualizar los controladores desde la BIOS.','Convertir archivos locales en copias de seguridad cifradas.'],0),q('¿Qué elemento del escritorio de Windows 11 se considera esencial para comenzar a practicar operaciones básicas?',['El escritorio con sus iconos, barra de tareas y paneles asociados.','La carcasa del teclado.','El cable Ethernet exclusivamente.','La batería del portátil, aunque sea un equipo de sobremesa.'],0),q('¿Qué diferencia básica hay entre Panel de control y Configuración?',['Ambos permiten gestionar ajustes, aunque Configuración ofrece una interfaz más moderna y orientada también a dispositivos táctiles.','Panel de control sirve solo para ver fotos y Configuración solo para escribir textos.','Configuración reemplaza por completo la seguridad del sistema y el Panel de control la desactiva.','No existe ninguna relación entre ambas herramientas.'],0),q('¿Desde qué herramienta se pueden revisar los dispositivos conectados al equipo y sus incidencias?',['Desde el Administrador de dispositivos.','Desde la calculadora de Windows.','Desde el explorador web.','Desde la barra espaciadora del teclado.'],0),q('¿Qué finalidad tiene BitLocker?',['Proteger la información mediante el cifrado de unidades.','Aumentar la velocidad de escritura en el teclado numérico.','Organizar automáticamente las ventanas del escritorio.','Reemplazar a las cuentas de usuario del sistema.'],0),q('¿Qué utilidad tienen las copias de seguridad en Windows 11?',['Permiten guardar datos y restaurarlos si se pierden o dañan.','Sirven únicamente para crear accesos directos.','Sustituyen la necesidad de guardar documentos mientras se trabaja.','Solo se utilizan en navegadores web.'],0),q('¿Qué ocurre normalmente con Seguridad de Windows si se instala otro antivirus compatible?',['Suele desactivarse automáticamente para evitar conflictos entre soluciones de protección.','Duplica los análisis para que el equipo vaya más lento.','Borra el contenido del explorador de archivos.','Se convierte en un programa de edición de texto.'],0),q('¿Qué permite realizar la aplicación Seguridad de Windows?',['Análisis rápidos y avanzados, además de revisar distintas áreas de protección.','Crear escritorios virtuales y organizar ventanas.','Desinstalar el sistema operativo sin confirmación.','Convertir bits en bytes de manera automática.'],0),q('¿Por qué es importante mantener Windows Update activado?',['Porque facilita recibir mejoras de seguridad y rendimiento mediante actualizaciones.','Porque bloquea el teclado numérico cuando hay errores.','Porque sustituye el antivirus instalado en el equipo.','Porque impide usar el explorador de archivos.'],0),q('¿Qué tipo de cuenta se menciona en el reto profesional del tema de sistema operativo?',['Una cuenta local de tipo Administrador para practicar diversas tareas de gestión.','Una cuenta bancaria para pagar licencias de software.','Una cuenta de invitado sin permisos para instalar aplicaciones.','Una cuenta de red creada automáticamente por el router.'],0),q('¿Qué relación guarda el sistema operativo con el trabajo administrativo?',['Es la base para gestionar archivos, usuarios, seguridad, aplicaciones y operaciones diarias del equipo.','Solo se utiliza en equipos de ocio y no en entornos laborales.','Se limita a mostrar la hora y el fondo de pantalla.','No interviene en la organización de documentos ni carpetas.'],0)],
internet:[q('¿Qué es Internet según el contenido trabajado?',['Una red mundial de redes que utiliza normas o protocolos comunes de comunicación.','Un único ordenador central al que se conectan todos los equipos.','Una aplicación de mensajería instalada en Windows 11.','Un programa exclusivo para descargar navegadores.'],0),q('¿Qué diferencia básica existe entre Internet, Intranet y Extranet?',['Internet es una red global, la Intranet se usa en entornos limitados y la Extranet conecta a la empresa con agentes externos autorizados.','Las tres expresiones significan exactamente lo mismo.','La Intranet es pública y la Internet privada.','La Extranet sustituye a los navegadores y la Internet a los antivirus.'],0),q('¿Qué función cumplen los protocolos TCP IP?',['Permitir la comunicación entre equipos mediante reglas comunes de transmisión de datos.','Sustituir el nombre de dominio por la contraseña del usuario.','Desactivar el firewall de Windows cuando la conexión falla.','Convertir el navegador en una herramienta de copias de seguridad.'],0),q('¿Para qué sirve el DNS?',['Relacionar nombres de dominio con direcciones IP para facilitar la localización de equipos y servicios.','Borrar automáticamente el historial de navegación.','Activar la navegación privada en cualquier navegador.','Comprobar si un archivo descargado tiene malware.'],0),q('¿Cuál de estos elementos suele ser necesario para acceder a Internet?',['Un proveedor de servicios, una línea de comunicación, un router y un equipo compatible.','Solo un teclado extendido y una impresora.','Una licencia de procesador de textos.','Únicamente una cuenta local de Windows sin red.'],0),q('¿Qué diferencia básica existe entre Wi Fi y Ethernet?',['Wi Fi es una conexión inalámbrica y Ethernet usa cable de red.','Ethernet funciona por ondas y Wi Fi solo con cable.','Ambas son tipos de antivirus.','Wi Fi sustituye al router y Ethernet al navegador.'],0),q('¿Qué navegador aparece como predeterminado en Windows 11?',['Microsoft Edge.','Firefox Focus.','Opera GX.','Brave.'],0),q('¿Qué medida puede mejorar la privacidad en un navegador?',['Activar la prevención de seguimiento y revisar los datos que se borran al cerrar.','Aceptar todas las cookies sin revisar la configuración.','Guardar automáticamente todos los formularios y métodos de pago.','Instalar extensiones sin comprobar su función.'],0),q('¿Qué caracteriza a la navegación privada de Firefox u otros navegadores similares?',['Reduce el almacenamiento local de ciertos datos de navegación en el equipo.','Hace que el equipo quede totalmente invisible en Internet para cualquier servicio.','Impide que el proveedor de Internet detecte la conexión.','Sustituye completamente la necesidad de antivirus.'],0),q('¿Qué es el malware?',['Software malicioso diseñado para dañar, robar o destruir datos.','Un programa oficial de mantenimiento incluido en todos los navegadores.','Una copia de seguridad cifrada en la nube.','Una tecnología de acceso inalámbrico de alta velocidad.'],0),q('¿Cuál de estos ejemplos es un tipo de malware?',['Ransomware.','Escritorio virtual.','Barra de tareas.','Licencia de software.'],0),q('¿Qué hábito ayuda a prevenir infecciones y riesgos en Internet?',['Evitar abrir enlaces o correos sospechosos y analizar archivos descargados.','Descargar cualquier archivo si la página tiene muchas imágenes.','Desactivar el antivirus para instalar programas con más rapidez.','Usar siempre la misma contraseña en todos los servicios.'],0),q('¿Para qué sirve OneDrive?',['Para almacenar y compartir archivos en la nube de Microsoft.','Para cifrar discos con BitLocker.','Para sustituir el sistema operativo del equipo.','Para bloquear la barra espaciadora.'],0),q('¿Qué rasgo define de forma sencilla la Web 2.0?',['Su dimensión social y participativa, con interacción entre usuarios.','Su limitación exclusiva a páginas estáticas sin interacción.','El uso exclusivo en entornos empresariales cerrados.','La sustitución total de los navegadores por aplicaciones locales.'],0),q('¿Qué se asocia a la evolución hacia la Web 3.0 y Web 4.0?',['Mayor capacidad semántica, personalización y uso de tecnologías como big data e inteligencia artificial.','La desaparición total de la seguridad y la privacidad.','La imposibilidad de almacenar contenido en la nube.','La eliminación de los nombres de dominio.'],0),q('¿Qué práctica aparece en el reto profesional sobre navegación segura?',['Actualizar el navegador, instalar extensiones de privacidad y activar la verificación en dos pasos.','Desactivar el firewall para acelerar la navegación.','Guardar los métodos de pago sin revisar permisos.','Abrir cualquier archivo descargado antes de analizarlo.'],0),q('¿Qué medida refuerza la seguridad de una cuenta en línea?',['Activar la verificación en dos pasos.','Compartir la contraseña con compañeros del aula.','Usar la misma clave en todos los servicios.','Desactivar las alertas de inicio de sesión.'],0),q('¿Qué conviene hacer con los datos de navegación si se busca aumentar la privacidad?',['Revisar la configuración y borrar historial, cookies y otros datos cuando proceda.','Mantener todo almacenado indefinidamente sin revisar opciones.','Guardar siempre los métodos de pago y los inicios de sesión en cualquier equipo.','Usar solo páginas sin comprobar el candado o el dominio.'],0),q('¿Qué aporta un antivirus integrado como Microsoft Defender?',['Capacidad para analizar archivos, detectar amenazas y ayudar a proteger el equipo.','La sustitución del navegador y del motor de búsqueda.','La creación automática de redes Wi Fi.','La eliminación de la necesidad de actualizar Windows.'],0),q('¿Qué idea resume mejor un uso responsable de las nuevas tecnologías?',['Aprovechar sus ventajas con criterios de seguridad, privacidad y sostenibilidad.','Conectar cualquier dispositivo sin revisar riesgos ni consumo.','Acumular archivos y descargas sin orden ni control.','Desactivar las medidas de protección para trabajar más deprisa.'],0)]};
const navItems=[{id:'inicio',label:'Inicio'},{id:'practica',label:'Práctica'},{id:'teoria',label:'Teoría'},{id:'tests',label:'Tests'},{id:'criterios',label:'Criterios'},{id:'docente',label:'Panel docente'}];
const state=loadState();let practice={studentName:state.studentName||'',phaseId:state.currentPhaseId||1,mode:state.currentMode||'normal',textIndex:0,startedAt:null,timer:null,completed:false,sourceText:''};
function loadState(){const raw=localStorage.getItem(APP_KEY);if(!raw)return{unlocked:[1],currentPhaseId:1,currentMode:'normal',studentName:'',attempts:{},allAttempts:[],dailySessions:[],testsPassed:{},teacherUnlocked:false,quizScore:{}};try{return JSON.parse(raw)}catch{return{unlocked:[1],currentPhaseId:1,currentMode:'normal',studentName:'',attempts:{},allAttempts:[],dailySessions:[],testsPassed:{},teacherUnlocked:false,quizScore:{}}}}
function saveState(){localStorage.setItem(APP_KEY,JSON.stringify(state));}
function todayKey(){const d=new Date();return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;}
function ensureDailySession(){const name=(practice.studentName||state.studentName||'Sin nombre').trim()||'Sin nombre';const day=todayKey();let entry=(state.dailySessions||[]).find(s=>s.day===day&&s.student===name);if(!entry){entry={day,student:name,practiceSeconds:0,attempts:0,phasesPassed:0,testPassed:0};state.dailySessions=state.dailySessions||[];state.dailySessions.push(entry);}return entry;}
function renderNav(){const nav=document.getElementById('nav');nav.innerHTML=navItems.map(item=>`<button class="${item.id===currentView()?'active':''}" data-view="${item.id}">${item.label}</button>`).join('');nav.querySelectorAll('button').forEach(btn=>btn.addEventListener('click',()=>showView(btn.dataset.view)));}
function currentView(){return document.querySelector('.view.active')?.id||'inicio';}
function showView(id){document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));document.getElementById(id).classList.add('active');renderNav();}
function getSelectedPhase(){return phases.find(p=>p.id===Number(practice.phaseId))||phases[0];}
function getPracticeCollection(phase){if(practice.mode==='english')return phase.englishTexts;if(practice.mode==='tables')return phase.tableTexts;return phase.texts;}
function getPracticeText(){const phase=getSelectedPhase();const collection=getPracticeCollection(phase);return collection[practice.textIndex%collection.length];}
function renderHome(){const host=document.getElementById('inicio');host.innerHTML=`<div class="hero"><div class="card"><span class="badge">Aplicación PRO</span><span class="badge">GitHub Pages</span><h2>Entrenamiento progresivo de mecanografía</h2><p class="small">Versión ampliada con práctica por fases, textos relacionados con los temas del módulo, cuatro bloques de test, seguimiento por alumno y acceso docente controlado.</p><div class="actions"><button class="button-main" id="goPractice">Ir a práctica</button><button class="button-soft" id="goTheory">Ver teoría</button><button class="button-soft" id="goTests">Abrir tests</button></div></div><div class="card"><h2>Ruta de aprendizaje</h2>${phases.map(p=>{const unlocked=state.unlocked.includes(p.id);return `<div class="phase ${unlocked?'':'locked'}"><h3>${p.title}</h3><div class="small">Objetivo: <strong>${p.targetPPM} ppm</strong> · Precisión máxima: <strong>${p.maxErrorsPerMinute} falta/min</strong></div><div class="small">${p.prompt}</div><div class="small"><span class="pill">${unlocked?'Desbloqueada':'Bloqueada'}</span></div></div>`;}).join('')}</div></div>`;document.getElementById('goPractice').onclick=()=>showView('practica');document.getElementById('goTheory').onclick=()=>showView('teoria');document.getElementById('goTests').onclick=()=>showView('tests');}
function renderPractice(){const host=document.getElementById('practica');const phase=getSelectedPhase();practice.sourceText=getPracticeText();const unlockedOptions=phases.filter(p=>state.unlocked.includes(p.id));host.innerHTML=`<div class="grid grid-2"><div class="card"><h2>Práctica guiada</h2><div class="row"><div><label>Nombre del alumno o alumna</label><input id="studentName" value="${escapeAttribute(practice.studentName||'')}" placeholder="Ejemplo: Lucía Pérez"></div><div><label>Fase</label><select id="phaseSelect">${unlockedOptions.map(p=>`<option value="${p.id}" ${p.id===phase.id?'selected':''}>${p.title}</option>`).join('')}</select></div><div><label>Modalidad</label><select id="modeSelect"><option value="normal" ${practice.mode==='normal'?'selected':''}>Texto alfanumérico</option><option value="tables" ${practice.mode==='tables'?'selected':''}>Tablas sencillas</option><option value="english" ${practice.mode==='english'?'selected':''}>Texto en inglés</option></select></div><div><label>Meta de la fase</label><input value="${phase.targetPPM} ppm · ${phase.maxErrorsPerMinute} falta/min" disabled></div></div><div class="stats"><div class="stat"><div class="label">Tiempo</div><div class="value" id="timeValue">00:00</div></div><div class="stat"><div class="label">PPM</div><div class="value" id="ppmValue">0</div></div><div class="stat"><div class="label">Precisión</div><div class="value" id="accValue">100%</div></div><div class="stat"><div class="label">Errores/min</div><div class="value" id="errMinValue">0</div></div></div><div id="targetText" class="typing-area"></div><div class="actions"><button class="button-main" id="newTextBtn">Cambiar texto</button><button class="button-soft" id="resetBtn">Reiniciar intento</button></div><label style="display:block;margin-top:14px;">Escribe aquí el texto:</label><textarea id="typingInput" placeholder="Empieza a escribir para iniciar el cronómetro..."></textarea><div id="practiceMessage"></div></div><div class="card"><h2>Desbloqueo y seguimiento</h2><p class="small">Cada fase dispone de al menos cinco textos por modalidad. Si el estudiante repite, no tiene por qué volver a ver el mismo texto de inmediato.</p><div class="resource"><strong>Fase actual:</strong> ${phase.title}<br><span class="small">Objetivo: ${phase.targetPPM} ppm · máximo ${phase.maxErrorsPerMinute} falta/min.</span><br><span class="small">Modalidad: <strong>${practice.mode==='normal'?'Texto alfanumérico':practice.mode==='tables'?'Tablas sencillas':'Texto en inglés'}</strong></span></div><div class="resource" style="margin-top:12px;"><strong>Introducir código manual</strong><p class="small">Introduce el código proporcionado por el profesorado para desbloquear la siguiente fase.</p><input id="codeInput" type="password" autocomplete="off" placeholder="Introduce el código"><div class="actions"><button class="button-soft" id="unlockBtn">Validar código</button></div><div id="unlockMessage"></div></div><div class="resource" style="margin-top:12px;"><strong>Últimos resultados</strong><div id="attemptsBox" class="small"></div></div></div></div>`;document.getElementById('studentName').addEventListener('input',e=>{practice.studentName=e.target.value;state.studentName=practice.studentName;saveState();});document.getElementById('phaseSelect').addEventListener('change',e=>{practice.phaseId=Number(e.target.value);state.currentPhaseId=practice.phaseId;practice.textIndex=0;stopTimer();saveState();renderPractice();});document.getElementById('modeSelect').addEventListener('change',e=>{practice.mode=e.target.value;state.currentMode=practice.mode;practice.textIndex=0;stopTimer();saveState();renderPractice();});document.getElementById('newTextBtn').onclick=()=>{practice.textIndex=(practice.textIndex+1)%getPracticeCollection(getSelectedPhase()).length;stopTimer();renderPractice();};document.getElementById('resetBtn').onclick=()=>{stopTimer();renderPractice();};document.getElementById('unlockBtn').onclick=handleCodeUnlock;document.getElementById('typingInput').addEventListener('input',handleTyping);renderTargetText('');renderAttempts();}
function renderTargetText(typed){const host=document.getElementById('targetText');const source=practice.sourceText||getPracticeText();host.innerHTML=source.split('').map((ch,i)=>{let cls='char';if(i<typed.length)cls+=typed[i]===ch?' correct':' incorrect';else if(i===typed.length)cls+=' current';return `<span class="${cls}">${escapeHtml(ch)}</span>`;}).join('');}
function handleTyping(e){const typed=e.target.value;if(!practice.startedAt&&typed.length>0)startTimer();renderTargetText(typed);updateStats(typed);}
function startTimer(){practice.startedAt=Date.now();practice.completed=false;practice.timer=setInterval(()=>{const typed=document.getElementById('typingInput')?.value||'';updateStats(typed,false);},250);}function stopTimer(){clearInterval(practice.timer);practice.timer=null;practice.startedAt=null;}
function updateStats(typed,finalize=true){const source=practice.sourceText||getPracticeText();const seconds=practice.startedAt?Math.max(1,Math.floor((Date.now()-practice.startedAt)/1000)):1;const minutes=seconds/60;let correct=0;let errors=0;for(let i=0;i<typed.length;i++){if(typed[i]===source[i])correct+=1;else errors+=1;}if(typed.length>source.length)errors+=typed.length-source.length;const ppm=Math.round(typed.length/minutes);const acc=typed.length?Math.round((correct/typed.length)*100):100;const errMin=Number((errors/minutes).toFixed(1));setText('timeValue',formatTime(seconds));setText('ppmValue',ppm);setText('accValue',`${acc}%`);setText('errMinValue',errMin);const phase=getSelectedPhase();const finished=typed.length>=source.length;if(finished&&!practice.completed&&finalize){practice.completed=true;clearInterval(practice.timer);const passed=ppm>=phase.targetPPM&&errMin<=phase.maxErrorsPerMinute;const key=`phase-${practice.phaseId}-${practice.mode}`;registerAttempt(key,{ppm,acc,errMin,errors,seconds,passed,mode:practice.mode});showPracticeResult({ppm,acc,errMin,passed,seconds});}}
function registerAttempt(key,result){if(!state.attempts[key])state.attempts[key]=[];const name=(practice.studentName||'Sin nombre').trim();const enriched={...result,student:name||'Sin nombre',phaseId:practice.phaseId,phaseTitle:getSelectedPhase().title,date:new Date().toLocaleString('es-ES')};state.attempts[key].unshift(enriched);state.attempts[key]=state.attempts[key].slice(0,10);state.allAttempts=state.allAttempts||[];state.allAttempts.unshift(enriched);state.allAttempts=state.allAttempts.slice(0,800);const daily=ensureDailySession();daily.practiceSeconds+=result.seconds||0;daily.attempts+=1;if(result.passed)daily.phasesPassed+=1;saveState();renderAttempts();}
function renderAttempts(){const box=document.getElementById('attemptsBox');if(!box)return;const attempts=state.attempts[`phase-${practice.phaseId}-${practice.mode}`]||[];if(!attempts.length){box.innerHTML='Todavía no hay intentos registrados en esta modalidad de la fase.';return;}box.innerHTML=attempts.map(a=>`<div style="padding:10px 0;border-bottom:1px solid var(--line);"><strong>${a.passed?'Superada':'No superada'}</strong> · ${a.ppm} ppm · ${a.errMin} faltas/min · ${a.acc}% precisión<br><span class="small">${a.student} · ${a.date}</span></div>`).join('');}
function showPracticeResult(result){const box=document.getElementById('practiceMessage');const phase=getSelectedPhase();if(result.passed){const next=phases.find(p=>p.id===phase.id+1);if(next&&!state.unlocked.includes(next.id)){state.unlocked.push(next.id);saveState();}box.innerHTML=`<div class="message ok">¡Reto superado! Resultado: ${result.ppm} ppm, ${result.acc}% de precisión y ${result.errMin} faltas por minuto.<br>${next?'Consulta al profesor para obtener el código de la siguiente fase.':'Has completado todas las fases del itinerario.'}</div>`;renderHome();renderPractice();}else{box.innerHTML=`<div class="message bad">Intento no superado. Debes alcanzar al menos ${phase.targetPPM} ppm y mantener como máximo ${phase.maxErrorsPerMinute} falta por minuto.</div>`;}}
function handleCodeUnlock(){const code=document.getElementById('codeInput').value.trim();const msg=document.getElementById('unlockMessage');if(code!==generateTodayCode()){msg.innerHTML='<div class="message bad">Código no válido.</div>';return;}const current=Number(practice.phaseId);const next=phases.find(p=>p.id===current+1);if(next&&!state.unlocked.includes(next.id)){state.unlocked.push(next.id);state.currentPhaseId=next.id;practice.phaseId=next.id;}saveState();msg.innerHTML=`<div class="message ok">${next?`Se ha desbloqueado ${next.title}.`:'Ya están desbloqueadas todas las fases.'}</div>`;setTimeout(renderPractice,250);renderHome();}
function renderTheory(){const host=document.getElementById('teoria');host.innerHTML=`<div class="card"><h2>Área teórica</h2><p class="small">Bloques alineados con los contenidos trabajados: operatoria de teclados, ergonomía, sistema operativo e Internet y seguridad.</p></div><div class="grid grid-2" style="margin-top:18px;">${theoryBlocks.map(block=>`<div class="card"><h3>${block.title}</h3><p class="small">${block.summary}</p><div class="resource"><iframe src="${block.embed}" title="${block.title}" allowfullscreen></iframe></div></div>`).join('')}</div>`;}
function buildRandomTest(topicId){const pool=[...testPools[topicId]];shuffle(pool);return pool.slice(0,15).map(item=>{const options=item.options.map((text,idx)=>({text,correct:idx===item.answerIndex}));shuffle(options);return{text:item.text,options,correctIndex:options.findIndex(o=>o.correct)};});}
function renderTests(){const host=document.getElementById('tests');const topics=[{id:'operatoria',label:'Test 1 · Operatoria de teclados',summary:'Principios de escritura al tacto, teclado, teclas, distribución de dedos y desarrollo de la destreza.'},{id:'ergonomia',label:'Test 2 · Ergonomía',summary:'Postura corporal, teclado, asiento, descansos y prevención de riesgos en el puesto informático.'},{id:'sistema',label:'Test 3 · Sistema Operativo',summary:'Conceptos básicos, Windows 11, gestión de archivos, configuración, seguridad y herramientas del sistema.'},{id:'internet',label:'Test 4 · Internet',summary:'Conexión a Internet, navegadores, privacidad, malware, nube y navegación segura.'}];host.innerHTML=`<div class="card"><h2>Bloques de test</h2><p class="small">Hay cuatro test temáticos. Cada intento carga 15 preguntas distintas de una batería amplia y mezcla el orden de preguntas y respuestas.</p></div><div class="grid grid-2" style="margin-top:18px;">${topics.map(t=>{const passed=state.testsPassed&&state.testsPassed[t.id];return `<div class="topic-card"><h3>${t.label}</h3><p class="small">${t.summary}</p><p class="small"><span class="pill">${passed?'Superado':'Pendiente'}</span></p><div class="actions"><button class="button-main" data-topic="${t.id}">Iniciar test</button></div><div id="topic-${t.id}"></div></div>`;}).join('')}</div>`;host.querySelectorAll('button[data-topic]').forEach(btn=>btn.addEventListener('click',()=>startTopicTest(btn.dataset.topic)));}
function startTopicTest(topicId){const mount=document.getElementById(`topic-${topicId}`);const test=buildRandomTest(topicId);mount.innerHTML=`<form id="form-${topicId}" class="card" style="margin-top:12px;">${test.map((item,idx)=>`<div class="question"><h4>${idx+1}. ${item.text}</h4>${item.options.map((opt,optIdx)=>`<label><input type="radio" name="q${idx}" value="${optIdx}"> ${opt.text}</label>`).join('')}</div>`).join('')}<div class="actions"><button type="submit" class="button-main">Corregir test</button></div><div id="result-${topicId}"></div></form>`;document.getElementById(`form-${topicId}`).addEventListener('submit',e=>{e.preventDefault();let score=0;test.forEach((item,idx)=>{const checked=mount.querySelector(`input[name="q${idx}"]:checked`);if(checked&&Number(checked.value)===item.correctIndex)score+=1;});const pass=score>=11;state.testsPassed=state.testsPassed||{};if(pass)state.testsPassed[topicId]=true;state.quizScore=state.quizScore||{};state.quizScore[topicId]=score;const daily=ensureDailySession();if(pass)daily.testPassed+=1;saveState();document.getElementById(`result-${topicId}`).innerHTML=`<div class="message ${pass?'ok':'warn'}">Resultado: <strong>${score}/15</strong>. ${pass?'Bloque superado.':'No superado todavía. Puedes intentarlo de nuevo y obtendrás otra combinación de preguntas.'}</div>`;renderTests();});}
function renderCriteria(){const host=document.getElementById('criterios');host.innerHTML=`<div class="card"><h2>Resultados de aprendizaje y criterios de evaluación</h2><p class="small">Referencia para alinear la práctica con la evaluación del módulo.</p></div><div class="grid grid-2" style="margin-top:18px;"><div class="card"><h3>Contenidos básicos</h3><ul class="clean small"><li>Proceso de textos alfanuméricos en teclados extendidos.</li><li>Organización del tiempo y del espacio de trabajo.</li><li>Postura corporal, ergonomía y prevención de tensiones.</li><li>Funciones de puesta en marcha del terminal informático.</li><li>Conocimiento del teclado extendido y uso de teclas especiales.</li><li>Desarrollo de la destreza mecanográfica con textos progresivos, tablas e inglés.</li><li>Conceptos básicos de sistema operativo e Internet seguro.</li></ul></div><div class="card"><h3>RA1 · Procesa textos alfanuméricos</h3><ul class="clean small"><li>Organiza los elementos y espacios de trabajo.</li><li>Mantiene la posición corporal correcta.</li><li>Identifica la posición correcta de los dedos en las filas del teclado.</li><li>Utiliza el método de escritura al tacto en párrafos progresivos, tablas sencillas y textos en inglés.</li><li>Alcanza 200 p.p.m. con máximo una falta por minuto con ayuda de un programa informático.</li><li>Localiza y corrige errores mecanográficos.</li></ul></div></div>`;}
function renderTeacher(){const host=document.getElementById('docente');if(!state.teacherUnlocked){host.innerHTML=`<div class="card" style="max-width:520px;margin:0 auto;"><h2>Acceso docente</h2><p class="small">Esta zona solo es accesible para el docente. Introduce el usuario docente para continuar.</p><input id="teacherUser" placeholder="Usuario docente"><div class="actions"><button class="button-main" id="teacherLogin">Acceder</button></div><div id="teacherLoginMsg"></div></div>`;document.getElementById('teacherLogin').onclick=()=>{const user=(document.getElementById('teacherUser').value||'').trim();if(user==='tmilgar'){state.teacherUnlocked=true;saveState();renderTeacher();}else{document.getElementById('teacherLoginMsg').innerHTML='<div class="message bad">Usuario docente no válido.</div>';}};return;}const summary=getStudentSummary();const sessions=(state.dailySessions||[]).slice().sort((a,b)=>(b.day+b.student).localeCompare(a.day+a.student));host.innerHTML=`<div class="grid grid-2"><div class="card"><h2>Panel docente</h2><p class="small">Acceso correcto. El código de desbloqueo permanece oculto en la interfaz del alumnado.</p>${phases.map(p=>`<div class="phase"><h3>${p.title}</h3><div class="small">Meta: ${p.targetPPM} ppm · Código oculto (uso docente)</div></div>`).join('')}<div class="actions"><button class="button-ghost" id="teacherLogout">Cerrar acceso docente</button></div></div><div class="card"><h2>Resumen por alumnado</h2>${summary.length?`<div style="overflow:auto;"><table><thead><tr><th>Alumno</th><th>Intentos</th><th>Fases superadas</th><th>Mejor PPM</th><th>Mejor precisión</th></tr></thead><tbody>${summary.map(s=>`<tr><td>${s.student}</td><td>${s.attempts}</td><td>${s.passed}</td><td>${s.bestPPM}</td><td>${s.bestAccuracy}%</td></tr>`).join('')}</tbody></table></div>`:`<div class="small">Todavía no hay datos guardados.</div>`}</div><div class="card"><h2>Registro diario local</h2><p class="small">Este seguimiento se guarda en el navegador del dispositivo donde se usa la aplicación. Para seguimiento realmente online y compartido entre varios equipos haría falta un backend o base de datos.</p>${sessions.length?`<div style="overflow:auto;"><table><thead><tr><th>Fecha</th><th>Alumno</th><th>Tiempo</th><th>Intentos</th><th>Fases superadas</th><th>Tests superados</th></tr></thead><tbody>${sessions.map(s=>`<tr><td>${s.day}</td><td>${s.student}</td><td>${formatTime(s.practiceSeconds||0)}</td><td>${s.attempts||0}</td><td>${s.phasesPassed||0}</td><td>${s.testPassed||0}</td></tr>`).join('')}</tbody></table></div>`:`<div class="small">Todavía no hay sesiones registradas.</div>`}</div><div class="card"><h2>Exportación</h2><div class="actions"><button class="button-main" id="exportAttempts">Exportar intentos CSV</button><button class="button-soft" id="exportSummary">Exportar resumen CSV</button><button class="button-soft" id="exportSessions">Exportar sesiones CSV</button><button class="button-warn" id="resetProgress">Borrar progreso local</button></div></div></div>`;document.getElementById('teacherLogout').onclick=()=>{state.teacherUnlocked=false;saveState();renderTeacher();};document.getElementById('exportAttempts').onclick=()=>exportCSV('attempts');document.getElementById('exportSummary').onclick=()=>exportCSV('summary');document.getElementById('exportSessions').onclick=()=>exportCSV('sessions');document.getElementById('resetProgress').onclick=()=>{localStorage.removeItem(APP_KEY);location.reload();};}
function getAllAttempts(){return state.allAttempts||[];}function getStudentSummary(){const grouped={};getAllAttempts().forEach(a=>{const name=a.student||'Sin nombre';if(!grouped[name])grouped[name]={student:name,attempts:0,passed:0,bestPPM:0,bestAccuracy:0};grouped[name].attempts+=1;if(a.passed)grouped[name].passed+=1;grouped[name].bestPPM=Math.max(grouped[name].bestPPM,a.ppm||0);grouped[name].bestAccuracy=Math.max(grouped[name].bestAccuracy,a.acc||0);});return Object.values(grouped).sort((a,b)=>b.bestPPM-a.bestPPM||b.bestAccuracy-a.bestAccuracy);}function exportCSV(type='attempts'){let rows=[];if(type==='summary'){rows=[['Alumno','Intentos','Fases superadas','Mejor PPM','Mejor precisión']].concat(getStudentSummary().map(r=>[r.student,r.attempts,r.passed,r.bestPPM,`${r.bestAccuracy}%`]));}else if(type==='sessions'){rows=[['Fecha','Alumno','Tiempo','Intentos','Fases superadas','Tests superados']].concat((state.dailySessions||[]).map(s=>[s.day,s.student,formatTime(s.practiceSeconds||0),s.attempts||0,s.phasesPassed||0,s.testPassed||0]));}else{rows=[['Alumno','Fecha','Fase','Modalidad','PPM','Precisión','Errores/min','Superada']].concat(getAllAttempts().map(r=>[r.student,r.date,r.phaseTitle,r.mode,r.ppm,`${r.acc}%`,r.errMin,r.passed?'Sí':'No']));}const csv=rows.map(row=>row.map(v=>`"${String(v).replaceAll('"','""')}"`).join(';')).join('\n');const blob=new Blob([csv],{type:'text/csv;charset=utf-8;'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=type==='summary'?'resumen_mecanografia.csv':type==='sessions'?'sesiones_mecanografia.csv':'intentos_mecanografia.csv';document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(url);}
function shuffle(arr){for(let i=arr.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[arr[i],arr[j]]=[arr[j],arr[i]];}return arr;}
function setText(id,value){const el=document.getElementById(id);if(el)el.textContent=value;}function formatTime(totalSeconds){const seconds=Math.max(0,Math.floor(totalSeconds||0));const h=Math.floor(seconds/3600);const m=Math.floor((seconds%3600)/60);const s=seconds%60;if(h>0)return `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`;return `${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`;}
function escapeAttribute(text){return String(text||'').replaceAll('&','&amp;').replaceAll('"','&quot;').replaceAll('<','&lt;').replaceAll('>','&gt;');}
function escapeHtml(text){return String(text||'').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#039;').replaceAll(' ','&nbsp;').replaceAll('\n','<br>');}
function init(){renderNav();renderHome();renderPractice();renderTheory();renderTests();renderCriteria();renderTeacher();}init();
